1	export interface QuoteItem {
2	  type: string;
3	  cursed?: boolean;
4	  enchantment?: number;
5	}
6	
7	export interface QuoteInput {
8	  items: QuoteItem[];
9	  customer: { yearsWithMHPCO: number };
10	  isFollowUp: boolean;
11	}
12	
13	const PROCESSING_FEE = 5;
14	const FIRST_INSURANCE_RATE = 0.1;
15	const BLOCK_OF_3_PREMIUM = 60;
16	const CURSED_SURCHARGE_RATE = 0.5;
17	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
18	const LOYALTY_DISCOUNT_RATE = 0.2;
19	const LOYALTY_THRESHOLD_YEARS = 2;
20	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
21	
22	const BASE_PREMIUM: Record<string, number> = {
23	  sword: 100,
24	  amulet: 60,
25	  staff: 80,
26	  potion: 40,
27	  rune: 25,
28	  moonstone: 25,
29	};
30	
31	export function quote(input: QuoteInput): number {
32	  let policyBase = 0;
33	
34	  const itemTypeCounts: Record<string, number> = {};
35	  for (const item of input.items) {
36	    itemTypeCounts[item.type] = (itemTypeCounts[item.type] || 0) + 1;
37	  }
38	
39	  for (const [type, count] of Object.entries(itemTypeCounts)) {
40	    if (count === 3) {
41	      policyBase += BLOCK_OF_3_PREMIUM;
42	    } else {
43	      policyBase += count * BASE_PREMIUM[type];
44	    }
45	  }
46	
47	  let itemSurcharges = 0;
48	  for (const item of input.items) {
49	    const itemBase = BASE_PREMIUM[item.type];
50	    if (item.cursed) {
51	      itemSurcharges += itemBase * CURSED_SURCHARGE_RATE;
52	    }
53	    if (item.enchantment !== undefined && item.enchantment >= 5) {
54	      itemSurcharges += itemBase * HIGH_ENCHANTMENT_SURCHARGE_RATE;
55	    }
56	  }
57	
58	  const loyaltyDiscount = input.customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? policyBase * LOYALTY_DISCOUNT_RATE : 0;
59	  const firstInsuranceSurcharge = policyBase * FIRST_INSURANCE_RATE;
60	  const followUpDiscount = input.isFollowUp ? policyBase * FOLLOW_UP_DISCOUNT_RATE : 0;
61	  const policyPremium = policyBase + itemSurcharges - loyaltyDiscount + firstInsuranceSurcharge - followUpDiscount;
62	  return Math.ceil(policyPremium + PROCESSING_FEE);
63	}
64	
65	export function claim() {
66	  return undefined;
67	}
